import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import DeleteOutlineIcon from '@mui/icons-material/DeleteOutline';
import ShoppingBagIcon from '@mui/icons-material/ShoppingBag';

const CartPage = () => {
  const { cart, cartLoading, updateQuantity, removeItem, clearCart } = useCart();
  const { user } = useAuth();
  const navigate = useNavigate();
  const [updating, setUpdating] = useState({});

  const handleQtyChange = async (item, delta) => {
    const newQty = item.quantity + delta;
    if (newQty < 1) return;
    const key = `${item.product._id}-${item.variant?.variantId}`;
    setUpdating((u) => ({ ...u, [key]: true }));
    try {
      await updateQuantity(item.product._id, item.variant?.variantId, newQty);
    } finally {
      setUpdating((u) => ({ ...u, [key]: false }));
    }
  };

  const shipping = cart.total >= 50 ? 0 : 5;
  const tax = Math.round(cart.total * 0.05 * 100) / 100;
  const total = cart.total + shipping + tax;

  if (!user) return (
    <div className="max-w-2xl mx-auto px-4 py-24 text-center">
      <p className="text-5xl mb-4">🛒</p>
      <h2 className="font-display text-2xl text-tea-900 mb-3">Sign in to view your cart</h2>
      <Link to="/login" className="btn-primary">Sign In</Link>
    </div>
  );

  if (cartLoading) return (
    <div className="max-w-5xl mx-auto px-4 py-12 animate-pulse">
      <div className="h-8 bg-tea-100 rounded w-1/4 mb-8" />
      {[1,2,3].map((i) => <div key={i} className="h-24 bg-tea-100 rounded-xl mb-4" />)}
    </div>
  );

  if (!cart.items || cart.items.length === 0) return (
    <div className="max-w-2xl mx-auto px-4 py-24 text-center">
      <p className="text-6xl mb-4">🍵</p>
      <h2 className="font-display text-2xl text-tea-900 mb-3">Your cart is empty</h2>
      <p className="text-gray-500 mb-8">Discover our collection of premium teas.</p>
      <Link to="/shop" className="btn-primary">Browse Teas</Link>
    </div>
  );

  return (
    <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
      <div className="flex items-center justify-between mb-8">
        <h1 className="font-display text-3xl text-tea-900">Your Cart</h1>
        <button onClick={clearCart} className="text-sm text-gray-400 hover:text-red-500 transition-colors">Clear all</button>
      </div>

      <div className="grid lg:grid-cols-3 gap-8">
        {/* Items */}
        <div className="lg:col-span-2 space-y-4">
          {cart.items.map((item) => {
            const key = `${item.product._id}-${item.variant?.variantId}`;
            const price = (item.priceAtAdd + (item.variant?.priceModifier || 0)) * item.quantity;
            return (
              <div key={key} className="card p-4 flex gap-4">
                <img
                  src={item.product.thumbnail || 'https://images.unsplash.com/photo-1556679343-c7306c1976bc?w=100'}
                  alt={item.product.name}
                  className="w-20 h-20 object-cover rounded-lg flex-shrink-0"
                />
                <div className="flex-1 min-w-0">
                  <div className="flex items-start justify-between gap-2">
                    <div>
                      <Link to={`/products/${item.product._id}`} className="font-medium text-tea-900 hover:text-tea-600 text-sm leading-tight">
                        {item.product.name}
                      </Link>
                      {item.variant?.name && (
                        <p className="text-xs text-gray-500 mt-0.5">{item.variant.name}</p>
                      )}
                    </div>
                    <button
                      onClick={() => removeItem(item.product._id, item.variant?.variantId)}
                      className="text-gray-400 hover:text-red-500 transition-colors flex-shrink-0"
                    >
                      <DeleteOutlineIcon fontSize="small" />
                    </button>
                  </div>
                  <div className="flex items-center justify-between mt-3">
                    <div className="flex items-center border border-gray-200 rounded-lg overflow-hidden">
                      <button
                        onClick={() => handleQtyChange(item, -1)}
                        disabled={updating[key]}
                        className="px-2.5 py-1 hover:bg-tea-50 text-gray-600 text-sm"
                      >−</button>
                      <span className="px-3 py-1 text-sm font-medium">{item.quantity}</span>
                      <button
                        onClick={() => handleQtyChange(item, 1)}
                        disabled={updating[key]}
                        className="px-2.5 py-1 hover:bg-tea-50 text-gray-600 text-sm"
                      >+</button>
                    </div>
                    <span className="font-semibold text-tea-800">${price.toFixed(2)}</span>
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        {/* Summary */}
        <div>
          <div className="card p-5 sticky top-20">
            <h2 className="font-display text-lg text-tea-900 mb-4">Order Summary</h2>
            <div className="space-y-3 text-sm">
              <div className="flex justify-between text-gray-600">
                <span>Subtotal</span>
                <span>${cart.total.toFixed(2)}</span>
              </div>
              <div className="flex justify-between text-gray-600">
                <span>Shipping</span>
                <span>{shipping === 0 ? <span className="text-sage-600 font-medium">Free</span> : `$${shipping.toFixed(2)}`}</span>
              </div>
              <div className="flex justify-between text-gray-600">
                <span>Tax (5%)</span>
                <span>${tax.toFixed(2)}</span>
              </div>
              {cart.total < 50 && (
                <p className="text-xs text-tea-600 bg-tea-50 px-3 py-2 rounded-lg">
                  Add ${(50 - cart.total).toFixed(2)} more for free shipping!
                </p>
              )}
              <div className="border-t border-tea-100 pt-3 flex justify-between font-semibold text-tea-900 text-base">
                <span>Total</span>
                <span>${total.toFixed(2)}</span>
              </div>
            </div>
            <button
              onClick={() => navigate('/checkout')}
              className="btn-primary w-full mt-5 py-3 flex items-center justify-center gap-2"
            >
              <ShoppingBagIcon fontSize="small" />
              Proceed to Checkout
            </button>
            <Link to="/shop" className="block text-center text-sm text-tea-600 hover:text-tea-800 mt-3">
              Continue Shopping
            </Link>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CartPage;
